// File: HomeViewModel.kt — the modern Android state pattern
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import kotlinx.coroutines.flow.*
import kotlinx.coroutines.launch

// 1. Repository — the SINGLE source of truth for User data. Combines net + DB.
class UserRepository(
  private val dao: UserDao,          // Room DAO
  private val api: UserApi,          // Retrofit
) {
  // Room DAOs can return a Flow — emits new data whenever the table changes
  fun observeUsers(): Flow<List<User>> = dao.observeUsers()

  suspend fun refresh() {
    val fresh = api.fetchUsers()      // network on IO by default
    dao.upsertAll(fresh)              // Flow above will re-emit
  }
}

// 2. UI state — a data class the UI consumes as one unit
data class HomeUi(
  val users: List<User> = emptyList(),
  val loading: Boolean = false,
  val error: String? = null,
)

// 3. ViewModel — survives rotation; state exposed as StateFlow
class HomeViewModel(private val repo: UserRepository) : ViewModel() {
  private val loading = MutableStateFlow(false)
  private val error   = MutableStateFlow<String?>(null)

  val ui: StateFlow<HomeUi> = combine(
    repo.observeUsers(),   // Flow<List<User>>
    loading,
    error,
  ) { users, isLoading, err -> HomeUi(users, isLoading, err) }
    .stateIn(viewModelScope, SharingStarted.WhileSubscribed(5_000), HomeUi(loading = true))

  fun refresh() {
    viewModelScope.launch {
      loading.value = true
      error.value = null
      try { repo.refresh() } catch (e: Exception) { error.value = e.message }
      loading.value = false
    }
  }
}

